FROM jsonb_to_recordset('[{"id": "cap-110-chinese-001", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "下列文句中的連詞，何者使用最恰當？", "options": ["即使生活變得富裕，也不應該浪費", "除非是很小的錯誤，也可能釀成大害", "只有從根本解決，就能為人民改善生活", "與其老師怎樣費心勸說，他還是我行我素"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   下列文句中的連詞，何者使用最恰當？\n     (A)即使生活變得富裕，也不應該浪費\n     (B)除非是很小的錯誤，也可能釀成大害\n     (C)只有從根本解決，就能為人民改善生活\n     (D)與其老師怎樣費心勸說，他還是我行我素\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-002", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「人生是短暫的，死亡是自然的，認清了這點，活著的時候才可以真正的投入。」\n這句話的涵義，與下列何者最接近？", "options": ["經歷死亡幽谷，才能發現活著的可貴", "能將死亡置之度外的人往往雖死猶生", "生命的價值在於不斷挑戰自我，安於現狀等於死亡", "了解生命的限制，坦然面對死亡，就能盡情地活著"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2. 「人生是短暫的，死亡是自然的，認清了這點，活著的時候才可以真正的投入。」\n   這句話的涵義，與下列何者最接近？\n   (A)經歷死亡幽谷，才能發現活著的可貴\n   (B)能將死亡置之度外的人往往雖死猶生\n   (C)生命的價值在於不斷挑戰自我，安於現狀等於死亡\n   (D)了解生命的限制，坦然面對死亡，就能盡情地活著\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-003", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "這是某相機使用說明書的一部分：\n對於以下主體，可能無法成功自動對焦：\n 與背景色彩相近的主體\n 自動對焦點同時覆蓋遠近主體\n 重複的圖案\n根據以上說明，這臺相機在相同的設定下，下列哪一個景物最容易自動對焦？", "options": ["雪地上的雪人", "欄杆後的盆栽", "沙漠中的綠色", "花色相同的馬 仙人掌       賽克磁磚"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.   這是某相機使用說明書的一部分：\n     對於以下主體，可能無法成功自動對焦：\n      與背景色彩相近的主體\n      自動對焦點同時覆蓋遠近主體\n      重複的圖案\n     根據以上說明，這臺相機在相同的設定下，下列哪一個景物最容易自動對焦？\n     (A)雪地上的雪人 (B)欄杆後的盆栽 (C)沙漠中的綠色 (D)花色相同的馬\n                            仙人掌       賽克磁磚\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-004", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "下列選項「」中的字，何組讀音相同？", "options": ["「恪」守本分／獨創一「格」", "「抵」死不從／蒞臨府「邸」", "字「斟」句酌／「勘」正訛誤", "鍾靈「毓」秀／才「疏」學淺"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 4, "raw_text": "4.   下列選項「」中的字，何組讀音相同？\n     (A)「恪」守本分／獨創一「格」\n     (B)「抵」死不從／蒞臨府「邸」\n     (C)字「斟」句酌／「勘」正訛誤\n     (D)鍾靈「毓」秀／才「疏」學淺\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-005", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「山田汽車成立於西元1916年。高橋汽車在山田汽車成立100週年時發表一段\n賀詞：『感謝100年來的競爭，沒有你的那30年有點孤獨。』」根據這段文\n字，高橋汽車最可能成立於西元哪一年？", "options": ["1816", "1846", "1886", "1946"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5. 「山田汽車成立於西元1916年。高橋汽車在山田汽車成立100週年時發表一段\n   賀詞：『感謝100年來的競爭，沒有你的那30年有點孤獨。』」根據這段文\n   字，高橋汽車最可能成立於西元哪一年？\n   (A)1816 (B)1846 (C)1886 (D)1946\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-006", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "਼ࣶ    Ӫ໩\n୉਼࣐ࣶȂуϑញሴ࣐ᅗཏ        યӶೞߴៗ‫ޠ‬ๆጣȂу㊆ᅉ\nӶР༬ԥ४‫ࣶޠ‬၈Ȃу᐀ԥ        ኅᚂณᜟ‫ޠ‬ЉӵȂᢛႷॴኹ\nՍϐ‫ޠ‬ስ஀Ȃ᐀ԥ໩ӏȃЬ        ႫႬϟֶᝌȄՅᄈܼೞᄪ‫׸‬\nпІޫ੊Ȅйၷ፞ӤᏕ۸ၽ        ႈӵ‫߇ޠ‬૪ᐚФࠍ༣ϟпቆ\n࣐ณិܼЙѵ‫ߧॴޠ‬уᡆൊ        ၷ፞ಘߺȂуᄀ‫ࣶڦ‬Ϝߞᆧ\n這首詩中「盆栽」對生活的態度，與下列何者最接近？", "options": ["安守現實，自得其樂", "享受挑戰，追求卓越", "突破藩籬，渴望自由", "寧為玉碎，不為瓦全"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6.\n                      ਼ࣶ    Ӫ໩\n       ୉਼࣐ࣶȂуϑញሴ࣐ᅗཏ        યӶೞߴៗ‫ޠ‬ๆጣȂу㊆ᅉ\n       ӶР༬ԥ४‫ࣶޠ‬၈Ȃу᐀ԥ        ኅᚂณᜟ‫ޠ‬ЉӵȂᢛႷॴኹ\n       Սϐ‫ޠ‬ስ஀Ȃ᐀ԥ໩ӏȃЬ        ႫႬϟֶᝌȄՅᄈܼೞᄪ‫׸‬\n       пІޫ੊Ȅйၷ፞ӤᏕ۸ၽ        ႈӵ‫߇ޠ‬૪ᐚФࠍ༣ϟпቆ\n       ࣐ณិܼЙѵ‫ߧॴޠ‬уᡆൊ        ၷ፞ಘߺȂуᄀ‫ࣶڦ‬Ϝߞᆧ\n\n     這首詩中「盆栽」對生活的態度，與下列何者最接近？\n     (A)安守現實，自得其樂 (B)享受挑戰，追求卓越\n     (C)突破藩籬，渴望自由 (D)寧為玉碎，不為瓦全\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-007", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "愛爾蘭文學家喬哀思流亡海外多年，其創作大多根植於早年在愛爾蘭 都柏林\n的生活。他曾說：「有一天，都柏林這座城市毀了，人們也可以憑藉我的小\n說，一磚一瓦的將之重建。」透過這句話可看出小說具有什麼作用？", "options": ["記錄地方文史風物", "勾勒未來生活圖象", "重振戰後失落的人心", "展現社區營造的力量"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7.   愛爾蘭文學家喬哀思流亡海外多年，其創作大多根植於早年在愛爾蘭 都柏林\n     的生活。他曾說：「有一天，都柏林這座城市毀了，人們也可以憑藉我的小\n     說，一磚一瓦的將之重建。」透過這句話可看出小說具有什麼作用？\n     (A)記錄地方文史風物  (B)勾勒未來生活圖象\n     (C)重振戰後失落的人心 (D)展現社區營造的力量\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-008", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「昔人未見麟，問嘗見者：『麟何類乎？』見者曰：『麟如麟也。』問者曰：\n『若吾嘗見麟，則不問子矣。而云麟如麟，寧可解哉？』見者曰：『麟者，麇1\n身牛尾，鹿蹄馬背。』問者豁然而解。」根據這則故事，下列敘述何者最恰當？", "options": ["問者蓄意為難，明知故問 ", "見者實未曾見麟，信口開河     1.麇：音ㄐㄩㄣ，形體似鹿之獸", "問者終不得其解，寧可自尋答案", "見者最後以具體事物為喻，輔助說明"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8.   「昔人未見麟，問嘗見者：『麟何類乎？』見者曰：『麟如麟也。』問者曰：\n     『若吾嘗見麟，則不問子矣。而云麟如麟，寧可解哉？』見者曰：『麟者，麇1\n     身牛尾，鹿蹄馬背。』問者豁然而解。」根據這則故事，下列敘述何者最恰當？\n     (A)問者蓄意為難，明知故問\n                         \n     (B)見者實未曾見麟，信口開河     1.麇：音ㄐㄩㄣ，形體似鹿之獸\n     (C)問者終不得其解，寧可自尋答案\n     (D)見者最後以具體事物為喻，輔助說明\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-009", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「落帆逗淮鎮，停舫臨孤驛。浩浩風起波，冥冥日沉夕。人歸山郭暗，雁下蘆洲\n白。獨夜憶秦關，聽鐘未眠客。」關於這首詩的分析，下列敘述何者最恰當？", "options": ["首兩句寫出與友餞別的地點與時間", "以「風起」、「日沉」自喻懷才不遇", "以「雁下蘆洲白」表示太陽將升起", "末兩句點出客因心有所思而不成眠"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9.   「落帆逗淮鎮，停舫臨孤驛。浩浩風起波，冥冥日沉夕。人歸山郭暗，雁下蘆洲\n     白。獨夜憶秦關，聽鐘未眠客。」關於這首詩的分析，下列敘述何者最恰當？\n     (A)首兩句寫出與友餞別的地點與時間\n     (B)以「風起」、「日沉」自喻懷才不遇\n     (C)以「雁下蘆洲白」表示太陽將升起\n     (D)末兩句點出客因心有所思而不成眠\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-010", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「獨創不代表完全嶄新，更非與傳統和過去截然無關。相反地，所有藝術的\n起點都來自於模仿與學習。什麼才是獨創？我們一生下來，世界就開始影響\n我們，而這種影響一直持續，直到我們過完此生。除了精力、氣力和意志以\n外，還有什麼是屬於我們自己的呢？」這段話的觀點與下列何者最接近？", "options": ["精力、氣力和意志有助於獨創", "獨創並不意味與傳統全然無關", "每件藝術品都必須以獨創為起點", "擺脫世界對我們的影響才能獨創"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. 「獨創不代表完全嶄新，更非與傳統和過去截然無關。相反地，所有藝術的\n    起點都來自於模仿與學習。什麼才是獨創？我們一生下來，世界就開始影響\n    我們，而這種影響一直持續，直到我們過完此生。除了精力、氣力和意志以\n    外，還有什麼是屬於我們自己的呢？」這段話的觀點與下列何者最接近？\n    (A)精力、氣力和意志有助於獨創\n    (B)獨創並不意味與傳統全然無關\n    (C)每件藝術品都必須以獨創為起點\n    (D)擺脫世界對我們的影響才能獨創\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-011", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "下列文句「」中的稱謂，何者使用最恰當？", "options": ["謝謝您的蒞臨，「貴校」蓬蓽生輝", "「小女」的于歸之宴，請您務必賞光", "「家弟」近期要搬家，忙得不可開交", "為了準備求職面試，「舍姐」緊張不已"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11. 下列文句「」中的稱謂，何者使用最恰當？\n    (A)謝謝您的蒞臨，「貴校」蓬蓽生輝\n    (B)「小女」的于歸之宴，請您務必賞光\n    (C)「家弟」近期要搬家，忙得不可開交\n    (D)為了準備求職面試，「舍姐」緊張不已\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-012", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「樹型直挺高壯的，無一不被畫上記號，陸續走向腰斬的命運。唯獨畸形虛\n弱的劣木，有的彎曲不直，有的枝枒過多，有的菌蟲蛀洞，有的矮小窄細，\n幸運地逃過一劫，殘喘至今，成了旅客心中敬畏的神木。」這段文字所要表\n達的意旨，與下列何者最接近？", "options": ["前事不忘，後事之師", "無用之用，是為大用", "一沙一世界，一花一天堂", "出淤泥而不染，濯清漣而不妖"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. 「樹型直挺高壯的，無一不被畫上記號，陸續走向腰斬的命運。唯獨畸形虛\n    弱的劣木，有的彎曲不直，有的枝枒過多，有的菌蟲蛀洞，有的矮小窄細，\n    幸運地逃過一劫，殘喘至今，成了旅客心中敬畏的神木。」這段文字所要表\n    達的意旨，與下列何者最接近？\n    (A)前事不忘，後事之師\n    (B)無用之用，是為大用\n    (C)一沙一世界，一花一天堂\n    (D)出淤泥而不染，濯清漣而不妖\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-013", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "小楓在古玩店看到一枚仿古錢幣，仔細一看，發現這是將\nϥ\nү    「唯」、「吾」、「知」、「足」四字字體共用「口」形，\n所合成的一個圖象。下列圖象何者也是用類似的方式合成？", "options": ["", "", "", "ሻ ‫ ڎ‬Κ ማ"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": ["option_incomplete"], "parse_confidence": 0.75, "original_question_number": 13, "raw_text": "13.         小楓在古玩店看到一枚仿古錢幣，仔細一看，發現這是將\n        ϥ\n       ү    「唯」、「吾」、「知」、「足」四字字體共用「口」形，\n            所合成的一個圖象。下列圖象何者也是用類似的方式合成？\n\n      (A)     (B)       (C)      (D)\n                                        ሻ\n                                       ‫ ڎ‬Κ\n                                        ማ"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-110-chinese-014", "exam_id": "cap", "subject_id": "sub-cap-chinese", "paper_id": "cap-110-chinese", "question_type": "single_choice", "question_text": "「許多科技大廠致力發展AI產業，但在支援中文化系統卻遇到困難。原因是\n中文的同音異字令語音辨識難度增加，而中文常與外語混用，以及次文化用\n語等都成為系統干擾。」根據這段文字，下列文句語音辨識錯誤的原因，何\n者未被提及？", "options": ["他是個勢利眼 → 他是個視力眼", "他在床上睡著了 → 他在船上睡著了", "班導要求按時交作業 → 扳倒要求按時交作業", "Facebook的用戶眾多 → 非死不可的用戶眾多"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T16:59:36+00:00", "source_pdf_sha1": "e0d22e4351f7", "answer_pdf_sha1": "bbb08ff8c483", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. 「許多科技大廠致力發展AI產業，但在支援中文化系統卻遇到困難。原因是\n    中文的同音異字令語音辨識難度增加，而中文常與外語混用，以及次文化用\n    語等都成為系統干擾。」根據這段文字，下列文句語音辨識錯誤的原因，何\n    者未被提及？\n    (A)他是個勢利眼 → 他是個視力眼\n    (B)他在床上睡著了 → 他在船上睡著了\n    (C)班導要求按時交作業 → 扳倒要求按時交作業\n    (D)Facebook的用戶眾多 → 非死不可的用戶眾多\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}]'::jsonb) AS t(
